import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = 'Unknown City',
    temperature = 0,
    condition = 'Clear',
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card 
      shadow="md" 
      padding={24} 
      radius="lg" 
      style={{ 
        background: 'var(--ggui-color-surface, #ffffff)',
        transition: 'box-shadow 200ms ease'
      }}
    >
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={3} color="var(--ggui-color-onSurface, #111827)">{city}</Heading>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #6b7280)">{condition}</Text>
        </Stack>

        <Stack align="center" gap={4}>
          <Heading level={1} color="var(--ggui-color-onSurface, #111827)">{temperature}°{unit}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #6b7280)">Current Temperature</Text>
        </Stack>

        <Stack direction="horizontal" justify="between">
          <Stack align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #6b7280)">Humidity</Text>
            <Text weight="semibold">{humidity}%</Text>
          </Stack>
          <Stack align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #6b7280)">Wind</Text>
            <Text weight="semibold">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider color="var(--ggui-color-outlineVariant, #e5e7eb)" />

        <Stack direction="horizontal" justify="between">
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #6b7280)">{item.day ?? '-'}</Text>
              <Text size="2xl">{item.icon ?? '?'}</Text>
              <Text variant="bodySmall">
                {item.high ?? 0}° / {item.low ?? 0}°
              </Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Card, Stack, Text, Input, Box, Badge, Divider } from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const categories = useMemo(() => Array.from(new Set(elements.map((e) => e.category).filter(Boolean))), [elements]);

  const filtered = useMemo(() => {
    const q = searchTerm.toLowerCase();
    return elements.filter(
      (e) => e.name?.toLowerCase().includes(q) || e.symbol?.toLowerCase().includes(q)
    );
  }, [elements, searchTerm]);

  const getCategoryColor = (category?: string) => {
    switch (category) {
      case 'noble-gas': return 'var(--ggui-color-info-200)';
      case 'nonmetal': return 'var(--ggui-color-warning-200)';
      case 'alkali-metal': return 'var(--ggui-color-primary-200)';
      case 'transition-metal': return 'var(--ggui-color-neutral-300)';
      default: return 'var(--ggui-color-neutral-100)';
    }
  };

  return (
    <Stack gap={24} padding={24}>
      <Stack gap={16} align="center">
        <Input 
          label="Search Elements" 
          placeholder="Filter by name or symbol..." 
          value={searchTerm} 
          onChange={setSearchTerm} 
        />
        <Stack direction="horizontal" gap={12} wrap>
          {categories.map((cat) => (
            <Badge key={cat} variant="default" pill>{cat}</Badge>
          ))}
        </Stack>
      </Stack>

      <Box style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(18, 1fr)', 
        gap: '4px',
        overflowX: 'auto',
        minWidth: '1000px'
      }}>
        {filtered.map((el) => (
          <Box 
            key={el.atomicNumber} 
            style={{ 
              gridRow: el.row, 
              gridColumn: el.col,
              cursor: 'pointer'
            }}
            onClick={() => setSelectedElement(el)}
          >
            <Card padding={8} shadow="sm">
              <Stack align="start">
                <Text variant="caption">{el.atomicNumber}</Text>
                <Text variant="bodyLarge" weight="bold" align="center" style={{ width: '100%' }}>
                  {el.symbol}
                </Text>
              </Stack>
            </Card>
          </Box>
        ))}
      </Box>

      {selectedElement && (
        <Card padding={24} shadow="lg">
          <Stack gap={12}>
            <Text variant="overline">Element Details</Text>
            <Stack direction="horizontal" gap={16} align="center">
              <Text size="4xl" weight="bold">{selectedElement.symbol}</Text>
              <Stack gap={0}>
                <Text variant="bodyLarge" weight="semibold">{selectedElement.name}</Text>
                <Text variant="bodySmall">Atomic Number: {selectedElement.atomicNumber}</Text>
              </Stack>
            </Stack>
            <Divider />
            <Stack direction="horizontal" gap={8}>
              <Text variant="label">Weight:</Text>
              <Text>{selectedElement.atomicWeight ?? 'N/A'}</Text>
            </Stack>
            <Stack direction="horizontal" gap={8}>
              <Text variant="label">Category:</Text>
              <Badge variant="primary">{selectedElement.category}</Badge>
            </Stack>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}
